import{_ as t,o as a,c as h,ag as e}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"[Admin] Kho tính năng: Quản lý Đơn hàng (OMS)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/admin-oms.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/admin-oms.md"}'),i={name:"99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/admin-oms.md"};function o(l,n,r,s,d,u){return a(),h("div",null,[...n[0]||(n[0]=[e('<h1 id="admin-kho-tinh-nang-quan-ly-đon-hang-oms" tabindex="-1">[Admin] Kho tính năng: Quản lý Đơn hàng (OMS) <a class="header-anchor" href="#admin-kho-tinh-nang-quan-ly-đon-hang-oms" aria-label="Permalink to &quot;[Admin] Kho tính năng: Quản lý Đơn hàng (OMS)&quot;">​</a></h1><table tabindex="0"><thead><tr><th style="text-align:left;">Phiên bản</th><th style="text-align:left;">Ngày</th><th style="text-align:left;">Sprint</th><th style="text-align:left;">Nội dung thay đổi</th><th style="text-align:left;">Người thực hiện</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>v1.0</strong></td><td style="text-align:left;">26/03/2026</td><td style="text-align:left;"><a href="./../../02-quan-ly-sprint/sprint-4-dat-cho-thanh-toan/01-yeu-cau-nghiep-vu">Sprint 4</a></td><td style="text-align:left;">Khởi tạo mô tả hệ thống OMS Admin</td><td style="text-align:left;">PO</td></tr></tbody></table><hr><p>Hệ thống quản lý trạng thái, dòng tiền (Order Management System) dành cho Quản trị viên.</p><h2 id="_1-ban-quan-tri-đon-hang-order-dashboard" tabindex="-1">1. Bản quản trị Đơn hàng (Order Dashboard) <a class="header-anchor" href="#_1-ban-quan-tri-đon-hang-order-dashboard" aria-label="Permalink to &quot;1. Bản quản trị Đơn hàng (Order Dashboard)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Danh sách đơn hàng toàn hệ thống.</li><li>Lọc theo trạng thái (Pending/Paid/Confirmed/Cancelled/Refunded).</li><li>Tìm kiếm theo mã đơn, SĐT khách, Tên tour.</li></ul></li></ul><h2 id="_2-quan-ly-thanh-toan-payment-reconciliation" tabindex="-1">2. Quản lý Thanh toán (Payment Reconciliation) <a class="header-anchor" href="#_2-quan-ly-thanh-toan-payment-reconciliation" aria-label="Permalink to &quot;2. Quản lý Thanh toán (Payment Reconciliation)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Đối soát (Reconcile) mã giao dịch ngân hàng/cổng thanh toán.</li><li>Xác nhận thanh toán thủ công cho trường hợp Chuyển khoản (Bank Transfer).</li></ul></li></ul><h2 id="_3-hoan-tien-huy-đon-refunds-cancellations" tabindex="-1">3. Hoàn tiền &amp; Hủy đơn (Refunds &amp; Cancellations) <a class="header-anchor" href="#_3-hoan-tien-huy-đon-refunds-cancellations" aria-label="Permalink to &quot;3. Hoàn tiền &amp; Hủy đơn (Refunds &amp; Cancellations)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Hệ thống phê duyệt yêu cầu hoàn tiền cho khách.</li><li>Tự động hoàn lại slot trống vào Inventory sau khi hủy.</li></ul></li></ul><h2 id="_4-quan-ly-voucher-vouchers-discount-cms" tabindex="-1">4. Quản lý Voucher (Vouchers &amp; Discount CMS) <a class="header-anchor" href="#_4-quan-ly-voucher-vouchers-discount-cms" aria-label="Permalink to &quot;4. Quản lý Voucher (Vouchers &amp; Discount CMS)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Tạo mã giảm giá (Code: VIVU10, VN2026).</li><li>Thiết lập hạn mức (Max uses) và thời gian hiệu lực.</li></ul></li></ul><hr><p><em>Hệ thống back-office cho vận hành.</em></p>',14)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
